import 'package:injectable/injectable.dart'; import '../../../core/constants/app_constants.dart'; import '../../../core/utils/app_logger.dart'; @injectable class ChunkedUploadService { Future<void> uploadInChunks(String url, List<int> data, {void Function(double)? onProgress}) async { final chunkSize = AppConstants.chunkSizeBytes; final total = data.length; int sent = 0; while (sent < total) { final end = (sent + chunkSize).clamp(0, total); final chunk = data.sublist(sent, end); sent = end; onProgress?.call(sent / total); AppLogger.debug('Upload progress: ${(sent/total*100).toStringAsFixed(0)}%'); } } }